info.codeblock:
apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: net-red
  namespace: kv1
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "net-red",
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "dataplane":"dpdk",
          "instanceName": "net-red",
          "instanceType": "vrf",
          "vrfTarget":"2:11"
        },
        "ipam": {
          "type": "host-local",
          "capabilities":{"ips":true},
          "ranges": [
            [
              {
                "subnet": "10.11.0.0/24",
                "gateway": "10.11.0.254"
              }
            ],
            [
              {
                "subnet": "2001:db8:10.11.0.0/120",
                "gateway": "2001:db8:10.11.0.254"
              }
            ]
          ],
          "routes": [
            { "dst": "0.0.0.0/0"},
            { "dst": "30.0.0.0/8", "gw": "10.11.0.254" },
            { "dst": "21.0.0.0/8", "gw": "10.11.0.254" },
            { "dst": "3ffe:ffff:0:01ff::1/64" }
          ]
        },
        "kubeConfig":"/var/home/core/kubeconfig"
      }
    ]
  }'

apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: net-yellow
  namespace: kv1
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "net-yellow",
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "dataplane":"dpdk",
          "instanceName": "net-yellow",
          "instanceType": "vrf",
          "vrfTarget":"2:12"
        },
        "ipam": {
          "type": "host-local",
          "capabilities":{"ips":true},
          "ranges": [
            [
              {
                "subnet": "10.12.0.0/24",
                "gateway": "10.12.0.254"
              }
            ],
            [
              {
                "subnet": "2001:db8:10.12.0.0/120",
                "gateway": "2001:db8:10.12.0.254"
              }
            ]
          ],
          "routes": [
            { "dst": "0.0.0.0/0"},
            { "dst": "30.0.0.0/8", "gw": "10.12.0.254" },
            { "dst": "21.0.0.0/8", "gw": "10.12.0.254" },
            { "dst": "3ffe:ffff:0:01ff::1/64" }
          ]
        },
        "kubeConfig":"/var/home/core/kubeconfig"
      }
    ]
  }'
